def calculate_query_cost(document, variables=None, max_cost=500):
    """
    Calculate the estimated cost of a GraphQL query based on field weights
    and list multipliers. This prevents resource exhaustion from deeply nested
    or wide queries without limiting what fields clients can request.
    """
    from graphql import parse
    from graphql.language.ast import (
        FieldNode,
        OperationDefinitionNode,
        InlineFragmentNode,
        FragmentSpreadNode,
    )

    # Fields that return lists get a multiplier
    LIST_FIELDS = {
        "products": 25,
        "reviews": 10,
        "categories": 10,
        "images": 10,
        "children": 5,
        "sellers": 10,
    }

    # Pagination-aware: if 'first' or 'limit' argument is provided, use that
    FIELD_BASE_COST = 1

    def get_list_size(field_node):
        """Extract pagination limit from arguments if present."""
        if field_node.arguments:
            for arg in field_node.arguments:
                if arg.name.value in ("first", "limit"):
                    if hasattr(arg.value, "value"):
                        return int(arg.value.value)
        field_name = field_node.name.value
        return LIST_FIELDS.get(field_name, 1)

    def compute_cost(selection_set, parent_multiplier=1):
        if selection_set is None:
            return 0

        cost = 0
        for selection in selection_set.selections:
            if isinstance(selection, FieldNode):
                field_name = selection.name.value

                # Skip introspection fields
                if field_name.startswith("__"):
                    continue

                multiplier = get_list_size(selection) if field_name in LIST_FIELDS else 1
                field_cost = FIELD_BASE_COST * parent_multiplier

                if selection.selection_set:
                    field_cost += compute_cost(
                        selection.selection_set,
                        parent_multiplier * multiplier,
                    )
                else:
                    field_cost = FIELD_BASE_COST * parent_multiplier

                cost += field_cost
            elif isinstance(selection, InlineFragmentNode):
                cost += compute_cost(selection.selection_set, parent_multiplier)
            elif isinstance(selection, FragmentSpreadNode):
                # Fragment spreads would need fragment definitions lookup;
                # for simplicity, add a flat cost
                cost += 10 * parent_multiplier

        return cost

    if isinstance(document, str):
        document = parse(document)

    total_cost = 0
    for definition in document.definitions:
        if isinstance(definition, OperationDefinitionNode):
            total_cost += compute_cost(definition.selection_set)

    return total_cost


class QueryCostLimiter(strawberry.extensions.SchemaExtension):
    """
    Strawberry schema extension that rejects queries exceeding a cost threshold.
    This is the primary defense against GraphQL abuse - it allows clients to
    request any combination of fields but prevents resource exhaustion.
    """

    def __init__(self, *, execution_context=None, max_cost: int = 500):
        self.max_cost = max_cost
        super().__init__(execution_context=execution_context)

    def on_operation(self):
        execution_context = self.execution_context
        document = execution_context.graphql_document
        if document:
            cost = calculate_query_cost(document, max_cost=self.max_cost)
            if cost > self.max_cost:
                from graphql import GraphQLError
                execution_context.errors = [
                    GraphQLError(
                        f"Query cost {cost} exceeds maximum allowed cost {self.max_cost}. "
                        f"Consider reducing the number of nested list fields or using pagination."
                    )
                ]
                # Return without yielding to prevent execution
                return
        yield


