class CategoryType:
    id: int
    name: str
    description: Optional[str]

    @strawberry.field
    def parent(self, info: Info) -> Optional["CategoryType"]:
        db: Session = info.context["db"]
        category = db.query(CategoryModel).get(self.id)
        if category and category.parent:
            return CategoryType(
                id=category.parent.id,
                name=category.parent.name,
                description=category.parent.description,
            )
        return None

    @strawberry.field
    def children(self, info: Info) -> List["CategoryType"]:
        db: Session = info.context["db"]
        category = db.query(CategoryModel).options(
            selectinload(CategoryModel.children)
        ).get(self.id)
        if category:
            return [
                CategoryType(id=c.id, name=c.name, description=c.description)
                for c in category.children
            ]
        return []

    @strawberry.field
    def products(self, info: Info, limit: int = 25) -> List["ProductType"]:
        limit = min(limit, 100)
        db: Session = info.context["db"]
        category = db.query(CategoryModel).options(
            selectinload(CategoryModel.products)
        ).get(self.id)
        if category:
            return [
                ProductType(
                    id=p.id,
                    name=p.name,
                    description=p.description,
                    price=p.price,
                )
                for p in category.products[:limit]
            ]
        return []


