@strawberry.type
class ProductType:
    id: int
    name: str
    description: Optional[str]
    price: float

    @strawberry.field
    def seller(self, info: Info) -> Optional[SellerType]:
        db: Session = info.context["db"]
        product = db.query(ProductModel).options(
            selectinload(ProductModel.seller)
        ).get(self.id)
        if product and product.seller:
            s = product.seller
            return SellerType(id=s.id, name=s.name, email=s.email, rating=s.rating)
        return None

    @strawberry.field
    def reviews(self, info: Info, limit: int = 25) -> List[ReviewType]:
        limit = min(limit, 100)
        db: Session = info.context["db"]
        reviews = (
            db.query(ReviewModel)
            .filter(ReviewModel.product_id == self.id)
            .limit(limit)
            .all()
        )
        return [
            ReviewType(
                id=r.id,
                reviewer_name=r.reviewer_name,
                content=r.content,
                rating=r.rating,
            )
            for r in reviews
        ]

    @strawberry.field
    def categories(self, info: Info) -> List[CategoryType]:
        db: Session = info.context["db"]
        product = db.query(ProductModel).options(
            selectinload(ProductModel.categories)
        ).get(self.id)
        if product:
            return [
                CategoryType(id=c.id, name=c.name, description=c.description)
                for c in product.categories
            ]
        return []

    @strawberry.field
    def images(self, info: Info) -> List[ImageType]:
        db: Session = info.context["db"]
        images = (
            db.query(ImageModel)
            .filter(ImageModel.product_id == self.id)
            .all()
        )
        return [
            ImageType(id=img.id, url=img.url, alt_text=img.alt_text)
            for img in images
        ]

    @strawberry.field
    def average_rating(self, info: Info) -> Optional[float]:
        db: Session = info.context["db"]
        from sqlalchemy import func
        result = (
            db.query(func.avg(ReviewModel.rating))
            .filter(ReviewModel.product_id == self.id)
            .scalar()
        )
        return round(float(result), 2) if result else None


