@strawberry.type
class Query:
    @strawberry.field
    def product(self, info: Info, id: int) -> Optional[ProductType]:
        db: Session = info.context["db"]
        product = db.query(ProductModel).get(id)
        if product:
            return ProductType(
                id=product.id,
                name=product.name,
                description=product.description,
                price=product.price,
            )
        return None

    @strawberry.field
    def products(
        self,
        info: Info,
        limit: int = 25,
        offset: int = 0,
        search: Optional[str] = None,
        min_price: Optional[float] = None,
        max_price: Optional[float] = None,
        category_id: Optional[int] = None,
        seller_id: Optional[int] = None,
    ) -> ProductConnection:
        # Enforce maximum page size to prevent abuse
        limit = min(limit, 100)
        offset = max(offset, 0)

        db: Session = info.context["db"]
        query = db.query(ProductModel)

        if search:
            # Parameterized query - SQLAlchemy handles escaping
            search_term = f"%{search}%"
            query = query.filter(
                ProductModel.name.ilike(search_term)
                | ProductModel.description.ilike(search_term)
            )

        if min_price is not None:
            query = query.filter(ProductModel.price >= min_price)

        if max_price is not None:
            query = query.filter(ProductModel.price <= max_price)

        if category_id is not None:
            query = query.filter(
                ProductModel.categories.any(CategoryModel.id == category_id)
            )

        if seller_id is not None:
            query = query.filter(ProductModel.seller_id == seller_id)

        total_count = query.count()
        products = query.offset(offset).limit(limit).all()

        items = [
            ProductType(
                id=p.id,
                name=p.name,
                description=p.description,
                price=p.price,
            )
            for p in products
        ]

        return ProductConnection(
            items=items,
            page_info=PageInfo(
                has_next_page=(offset + limit) < total_count,
                has_previous_page=offset > 0,
                total_count=total_count,
            ),
        )

    @strawberry.field
    def categories(self, info: Info, top_level_only: bool = False) -> List[CategoryType]:
        db: Session = info.context["db"]
        query = db.query(CategoryModel)
        if top_level_only:
            query = query.filter(CategoryModel.parent_id.is_(None))
        categories = query.all()
        return [
            CategoryType(id=c.id, name=c.name, description=c.description)
            for c in categories
        ]

    @strawberry.field
    def category(self, info: Info, id: int) -> Optional[CategoryType]:
        db: Session = info.context["db"]
        category = db.query(CategoryModel).get(id)
        if category:
            return CategoryType(
                id=category.id,
                name=category.name,
                description=category.description,
            )
        return None

    @strawberry.field
    def seller(self, info: Info, id: int) -> Optional[SellerType]:
        db: Session = info.context["db"]
        seller = db.query(SellerModel).get(id)
        if seller:
            return SellerType(
                id=seller.id,
                name=seller.name,
                email=seller.email,
                rating=seller.rating,
            )
        return None

    @strawberry.field
    def sellers(self, info: Info, limit: int = 25) -> List[SellerType]:
        limit = min(limit, 100)
        db: Session = info.context["db"]
        sellers = db.query(SellerModel).limit(limit).all()
        return [
            SellerType(id=s.id, name=s.name, email=s.email, rating=s.rating)
            for s in sellers
        ]


# ============================================================
# Schema with Security Extensions
# ============================================================

# QueryDepthLimiter: prevents deeply nested queries (e.g., product -> seller -> products -> seller -> ...)
# QueryCostLimiter: prevents wide/expensive queries based on estimated cost
# Together they allow clients to fetch any combination of related data while
# preventing resource exhaustion attacks.

schema = Schema(
    query=Query,
    extensions=[
        QueryDepthLimiter(max_depth=10),
        QueryCostLimiter,
    ],
)


